const input = ($input.all()[0] && $input.all()[0].json) || {};
const chatId = input.chat_id;
const comando = input.comando || 'crear';
const textRaw = String(input.text || '');
const payload = input.payload || {};

let fecha = payload.fecha || '';
let slot = payload.slot || '';
let rango = payload.rango || '';
let fechaRaw = payload.fecha_raw || '';
let accion = '';
let mensajeError = '';

// Defensa: parsear callbacks que el orquestador no haya procesado
if (textRaw.startsWith('cmd:crear:slot:')) {
  const parsed = textRaw.substring('cmd:crear:slot:'.length);
  if (parsed !== 'none') slot = parsed;
}

// Si hay rango (botón) y no hay fecha, calcular fecha exacta
if (!fecha && rango && rango !== 'exacto') {
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  let daysToAdd = 0;
  if (rango === 'inmediato') daysToAdd = 1;
  else if (rango === '2semanas') daysToAdd = 14;
  else if (rango === '1mes') daysToAdd = 28;
  if (daysToAdd > 0) {
    today.setDate(today.getDate() + daysToAdd);
    fecha = today.toISOString().slice(0, 10);
  }
}

// Si hay fechaRaw (input DD/MM/AAAA) y no hay fecha, validar y convertir
if (!fecha && fechaRaw) {
  const match = /^(\d{2})\/(\d{2})\/(\d{4})$/.exec(fechaRaw);
  if (match) {
    const day = parseInt(match[1], 10);
    const month = parseInt(match[2], 10) - 1;
    const year = parseInt(match[3], 10);
    const parsed = new Date(year, month, day);
    if (parsed.getDate() === day && parsed.getMonth() === month && parsed.getFullYear() === year) {
      const today = new Date();
      today.setHours(0, 0, 0, 0);
      const maxDate = new Date(today);
      maxDate.setMonth(maxDate.getMonth() + 3);
      if (parsed < today) {
        accion = 'fecha_invalida';
        mensajeError = 'La fecha está en el pasado.';
      } else if (parsed > maxDate) {
        accion = 'fecha_invalida';
        mensajeError = 'Solo podés reservar hasta 3 meses adelante.';
      } else {
        fecha = parsed.toISOString().slice(0, 10);
      }
    } else {
      accion = 'fecha_invalida';
      mensajeError = 'La fecha no es válida (día o mes incorrecto).';
    }
  } else {
    accion = 'fecha_invalida';
    mensajeError = 'Formato incorrecto. Usá DD/MM/AAAA (ej: 15/07/2026).';
  }
}

// Decidir accion final
if (!accion) {
  if (rango === 'exacto' && !fecha) {
    accion = 'pedir_fecha';
  } else if (fecha && slot) {
    accion = 'crear_turno';
  } else if (fecha) {
    accion = 'pedir_slot';
  } else {
    accion = 'pedir_rango';
  }
}

return [{
  json: {
    chat_id: chatId,
    comando: comando,
    accion: accion,
    fecha: fecha,
    slot: slot,
    rango: rango,
    fecha_inicio: fecha || '',
    mensaje_error: mensajeError
  }
}];

const input = ($input.all()[0] && $input.all()[0].json) || {};
const chatId = input.chat_id;
const fecha = input.fecha || '';

let slots = [];
if (Array.isArray(input)) {
  slots = input;
} else if (Array.isArray(input.slots)) {
  slots = input.slots;
}
slots = slots.filter(function (s) { return s.disponible !== false; });

// Leer fecha_inicio del Code - Decidir Paso original (sobrevive al loop)
let fechaInicio = fecha;
try {
  const codeData = $('Code - Decidir Paso').first().json;
  if (codeData && codeData.fecha_inicio) {
    fechaInicio = codeData.fecha_inicio;
  }
} catch (e) {
  // fallback silencioso
}

// Contador en staticData, keyed por chat_id (soporta múltiples usuarios)
const staticData = $getWorkflowStaticData('global');
const contadorKey = 'contador_' + chatId;
let contador = staticData[contadorKey] || 0;

if (slots.length > 0) {
  // Encontrado - limpiar estado
  delete staticData[contadorKey];
  return [{
    json: {
      chat_id: chatId,
      fecha: fecha,
      fecha_inicio: fechaInicio,
      slots: slots,
      decision: 'found'
    }
  }];
}

// No hay slots. ¿Ya intentamos los 7 días?
const MAX_DIAS = 7;
if (contador >= MAX_DIAS - 1) {
  delete staticData[contadorKey];
  return [{
    json: {
      chat_id: chatId,
      fecha: fecha,
      fecha_inicio: fechaInicio,
      slots: [],
      decision: 'exhausted'
    }
  }];
}

// Retry: +1 día
staticData[contadorKey] = contador + 1;
const nextDate = new Date(fecha + 'T00:00:00');
nextDate.setDate(nextDate.getDate() + 1);
const nextFecha = nextDate.toISOString().slice(0, 10);

return [{
  json: {
    chat_id: chatId,
    fecha: nextFecha,
    fecha_inicio: fechaInicio,
    slots: [],
    decision: 'retry'
  }
}];

const input = ($input.all()[0] && $input.all()[0].json) || {};
const chatId = input.chat_id;
const fecha = input.fecha || '';
let slots = input.slots || [];
if (!Array.isArray(slots)) slots = [];
const disponibles = slots.filter(function (s) { return s.disponible !== false; });
return [{
  json: {
    chat_id: chatId,
    fecha: fecha,
    slots: disponibles,
    cantidad: disponibles.length
  }
}];

const input = ($input.all()[0] && $input.all()[0].json) || {};
const chatId = input.chat_id;
const fecha = input.fecha;
const slot = input.hora_inicio || input.slot;
const turnoId = input.id;
const errorStatus = input.statusCode && input.statusCode >= 400;
const errorDetail = input.detail || (errorStatus ? 'Error HTTP ' + input.statusCode : null);

return [{
  json: {
    chat_id: chatId,
    fecha: fecha,
    slot: slot,
    turno_id: turnoId,
    exito: !!turnoId && !errorStatus,
    error: errorDetail
  }
}];
